import Autocomplete from '@mui/material/Autocomplete';
import Box from '@mui/material/Box';
import Button from '@mui/material/Button';
import Card from '@mui/material/Card';
import CardContent from '@mui/material/CardContent';
import TextField from '@mui/material/TextField';
import Typography from '@mui/material/Typography';
import { Container, display } from '@mui/system';
import Cookies from 'js-cookie';
import { useEffect, useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { setUser } from '../store/auth.js';
const InitialForm = {
  label: '',
  icon: '',
};

const icons = ['User'];

export default function CategoryForm({ editCategory }) {
  const user = useSelector((state) => state.auth.user);
  const dispatch = useDispatch();
  const token = Cookies.get('token');
  const [form, setForm] = useState(InitialForm);

  useEffect(() => {
    if (editCategory._id !== undefined) {
      setForm(editCategory);
    }
  }, [editCategory]);

  function handleChange(e) {
    setForm({ ...form, [e.target.name]: e.target.value });
  }

  function handleDate(newValue) {
    setForm({ ...form, date: newValue });
  }

  async function handleSubmit(e) {
    e.preventDefault();
    editCategory._id === undefined ? create() : update();
  }

  function reload(res, _user) {
    if (res.ok) {
      dispatch(setUser({ user: _user }));
      setForm(InitialForm);
    }
  }

  async function create() {
    const res = await fetch(`${process.env.REACT_APP_API_URL}/category`, {
      method: 'POST',
      body: JSON.stringify(form),
      headers: {
        'content-type': 'application/json',
        Authorization: `Bearer ${token}`,
      },
    });
    const _user = {
      ...user,
      categories: [...user.categories, { ...form }],
    };
    reload(res, _user);
  }

  async function update() {
    const res = await fetch(
      `${process.env.REACT_APP_API_URL}/category/${editCategory._id}`,
      {
        method: 'PATCH',
        body: JSON.stringify(form),
        headers: {
          'content-type': 'application/json',
          Authorization: `Bearer ${token}`,
        },
      }
    );
    const _user = {
      ...user,
      categories: user.categories.map((cat) =>
        cat._id == editCategory._id ? form : cat
      ),
    };
    reload(res, _user);
  }

  function getCategoryNameById() {
    return (
      user.categories.find((category) => category._id === form.category_id) ??
      ''
    );
  }

  return (
    <Card sx={{ minWidth: 275, marginTop: 10 }}>
      <CardContent>
        <Typography variant='h4'>Filter</Typography>
        <Box component='form' onSubmit={handleSubmit} sx={{ display: 'block' }}>
          <Typography variant='h6'>Prices</Typography>
          {/* <TextField
            sx={{ marginRight: 5 }}
            id='outlined-basic'
            label='Label'
            type='text'
            size='small'
            name='label'
            variant='outlined'
            value={form.label}
            onChange={handleChange}
          /> */}
          {/* <form>
            <div sx={{ width: '20px', display: 'inline-block' }}>
              <input type='radio' value='Male' sx={{ margin: '0px' }} />
              <span sx={{ margin: '3px 3px 0px 0' }}>Less than 1000</span>
            </div>
            <div sx={{ width: '20px', display: 'inline-block' }}>
              <input type='radio' value='Male' sx={{ margin: '0px' }} />
              <span sx={{ margin: '3px 3px 0px 0' }}>1000 - 5000</span>
            </div>
            <div sx={{ width: '20px' }}>
              <input type='radio' value='Male' sx={{ margin: '0px' }} />
              <span sx={{ margin: '3px 3px 0px 0' }}>5000 - 10000</span>
            </div>
            <div sx={{ width: '20px' }}>
              <input type='radio' value='Male' sx={{ margin: '0px' }} />
              <span sx={{ margin: '3px 3px 0px 0' }}>Greater than 10000</span>
            </div>
          </form> */}
          {/* <form>
            <div className='radio'>
              <label>
                <input type='radio' value='option1' checked={true} />
                Option 1
              </label>
            </div>
            <div className='radio'>
              <label>
                <input type='radio' value='option2' />
                Option 2
              </label>
            </div>
            <div className='radio'>
              <label>
                <input type='radio' value='option3' />
                Option 3
              </label>
            </div>
          </form> */}
          <FormControl>
            <FormLabel id='demo-radio-buttons-group-label'>Gender</FormLabel>
            <RadioGroup
              aria-labelledby='demo-radio-buttons-group-label'
              defaultValue='female'
              name='radio-buttons-group'
            >
              <FormControlLabel
                value='female'
                control={<Radio />}
                label='Female'
              />
              <FormControlLabel value='male' control={<Radio />} label='Male' />
              <FormControlLabel
                value='other'
                control={<Radio />}
                label='Other'
              />
            </RadioGroup>
          </FormControl>
          <Autocomplete
            value={getCategoryNameById()}
            onChange={(event, newValue) => {
              setForm({ ...form, icon: newValue });
            }}
            id='icons'
            options={icons}
            sx={{ width: 200, marginRight: 5 }}
            renderInput={(params) => (
              <TextField {...params} size='small' label='Icon' />
            )}
          />
          {editCategory._id !== undefined && (
            <Button type='submit' variant='secondary'>
              Update
            </Button>
          )}
          {editCategory._id === undefined && (
            <Button type='submit' variant='contained'>
              Submit
            </Button>
          )}
        </Box>
      </CardContent>
    </Card>
  );
}
